import{_ as d,o as e,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt4501.jpg",i="/images/lekt4502.jpg",k=JSON.parse('{"title":"Lektion 45","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion45.md","filePath":"lektionen/lektion45.md"}'),s={name:"lektionen/lektion45.md"};function l(o,t,h,u,m,p){return e(),r("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-45" tabindex="-1">Lektion 45 <a class="header-anchor" href="#lektion-45" aria-label="Permalink to &quot;Lektion 45&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>45.1. Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix (Fortsetzung) <ul><li>45.1.1. Dritte Präsensklasse (जुहोत्यादि)</li><li>45.1.2. Siebte Präsensklasse (रुधादि)</li></ul></li><li>45.2. Der Vokativ Singular (आमन्त्रितमेकवचने)</li><li>45.3. Wortliste</li><li>45.4. Übung</li></ul><h2 id="_45-1-bildung-der-verbalformen-der-2-person-मध्यमः-athematischer-stamme-ohne-vokalisch-endendem-suffix-fortsetzung" tabindex="-1">45.1. Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix (Fortsetzung) <a class="header-anchor" href="#_45-1-bildung-der-verbalformen-der-2-person-मध्यमः-athematischer-stamme-ohne-vokalisch-endendem-suffix-fortsetzung" aria-label="Permalink to &quot;45.1. Bildung der Verbalformen der 2. Person (मध्यमः) athematischer Stämme ohne vokalisch endendem Suffix (Fortsetzung)&quot;">​</a></h2><h3 id="_45-1-1-dritte-prasensklasse-जुहोत्यादि" tabindex="-1">45.1.1. Dritte Präsensklasse (जुहोत्यादि) <a class="header-anchor" href="#_45-1-1-dritte-prasensklasse-जुहोत्यादि" aria-label="Permalink to &quot;45.1.1. Dritte Präsensklasse (जुहोत्यादि)&quot;">​</a></h3><p>हु 3P</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>जुहोषि</td><td>जुहुथ</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अजुहोस्</td><td>अजुहुत</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>जुहुयास्</td><td>जुहुयात</td></tr></tbody></table></blockquote><p>धा 2U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>दधासि</td><td>धत्थ</td></tr><tr><td>aus: dadh + tha</td><td>धत्से</td><td>धद्ध्वे</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अदधास्</td><td>अधत्त</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>दध्यास्</td><td>दध्यात</td></tr></tbody></table></blockquote><h3 id="_45-1-2-siebte-prasensklasse-रुधादि" tabindex="-1">45.1.2. Siebte Präsensklasse (रुधादि) <a class="header-anchor" href="#_45-1-2-siebte-prasensklasse-रुधादि" aria-label="Permalink to &quot;45.1.2. Siebte Präsensklasse (रुधादि)&quot;">​</a></h3><p>Wenn auslautendes k/g der Wurzel zwischen den Nasal ṅ und einen Dental der Endung zu stehen kommt, so kann wahlweise das k/g wegfallen</p><p>z.B. युज् 3.sg.Ind.Präs.Ā युङ्क्ते oder युङ्ते</p><p>युज् 7U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>युनक्षि</td><td></td></tr><tr><td>yu-na-j + si</td><td>युङ्क्थ</td><td></td></tr><tr><td>युङ्थ</td><td>युङ्क्षे</td><td>युङ्ग्ध्वे</td></tr><tr><td>युङ्ध्वे</td><td></td><td></td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अयुनक्</td><td></td></tr><tr><td>aus: a-yu-na-j + s</td><td>युङ्क्त</td><td></td></tr><tr><td>अयुङ्त</td><td>अयुङ्क्थास्</td><td></td></tr><tr><td>अयुङ्थास्</td><td>अयुङ्ग्ध्वम्</td><td></td></tr><tr><td>अयुङ्ध्वम्</td><td></td><td></td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>युञ्ज्यास्</td><td>युञ्ज्यात</td></tr></tbody></table></blockquote><p>रुध् 7U</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>Indikativ Präsens</td><td></td><td></td></tr><tr><td>लट्</td><td>रुणत्सि</td><td></td></tr><tr><td>ru + na + dh + si</td><td>रुन्द्ध</td><td></td></tr><tr><td>ru-n-dh + tha</td><td>रुन्त्से</td><td>रुन्द्ध्वे</td></tr><tr><td>Imperfekt</td><td></td><td></td></tr><tr><td>लङ्</td><td>अरुणत्</td><td></td></tr><tr><td>aus a-ru-ṇa-dh + s</td><td></td><td></td></tr><tr><td>अरुण्स् (unregelm.!)</td><td>अरुन्द्ध</td><td></td></tr><tr><td>a-ru-n-dh + ta</td><td>अरुन्द्धास्</td><td>अरुन्द्ध्वम्</td></tr><tr><td>Optativ</td><td></td><td></td></tr><tr><td>विधिलिङ्</td><td>रुन्ध्यास्</td><td>रुन्ध्यात</td></tr></tbody></table></blockquote><h2 id="_45-2-der-vokativ-singular-आमन्त्रितमेकवचने" tabindex="-1">45.2. Der Vokativ Singular (आमन्त्रितमेकवचने) <a class="header-anchor" href="#_45-2-der-vokativ-singular-आमन्त्रितमेकवचने" aria-label="Permalink to &quot;45.2. Der Vokativ Singular (आमन्त्रितमेकवचने)&quot;">​</a></h2><p>Die meisten Vokative des Singular sind</p><p>der Stamm mit hochstufigem Auslaut.</p><p>z.B. देव, कवे, शत्रो, राजन्, पितर् u.s.w.</p><p>Ausnahmen sind die Feminina auf -ā und -ī sowie die Stämme auf -in, deren Vokativ sg. besonders zu merken ist.</p><table tabindex="0"><thead><tr><th></th><th>Vokativ Singular</th></tr></thead><tbody><tr><td>Maskulina auf -a</td><td>देव</td></tr><tr><td>Neutra auf -a</td><td>फल</td></tr><tr><td>Feminina auf -ā</td><td>देवते</td></tr><tr><td>Maskulina auf -i</td><td>कवे</td></tr><tr><td>Feminina auf -i</td><td>मते</td></tr><tr><td>Maskulina auf -u</td><td>शत्रो</td></tr><tr><td>Feminina auf -u</td><td>धेनो</td></tr><tr><td>Feminina auf -ī</td><td>देवि</td></tr><tr><td>Maskulina auf -ṛ</td><td>पितर्</td></tr><tr><td>Feminina auf -ṛ</td><td>मातर्</td></tr><tr><td>Maskulina auf -an</td><td>राजन्</td></tr><tr><td>Neutra auf -an</td><td>नामन्</td></tr><tr><td>नाम</td><td></td></tr><tr><td>Maskulina auf -man/-van</td><td>आत्मन्</td></tr><tr><td>Maskulina auf -in</td><td>बलिन्</td></tr><tr><td>Maskulina auf -ant</td><td>बलिन्</td></tr><tr><td>बलि</td><td></td></tr><tr><td>mahānt m.</td><td>महन्</td></tr><tr><td>mahānt n.</td><td>महत्</td></tr><tr><td>= Nominativ</td><td></td></tr><tr><td>Maskulina auf -mant/-vant</td><td>गुणवन्</td></tr><tr><td>Neutra auf -mant/-vant</td><td>गुणवत्</td></tr><tr><td>= Nominativ</td><td></td></tr><tr><td>Pronomina</td><td>ein Vokativ wird nicht gebildet</td></tr></tbody></table><p><img src="'+n+'" alt=""><br> Abb.: भवति किं करोषि<br> Textil-Blockdruck, Ahmedabad<br> [Bildquelle: Daveybot. -- <a href="http://www.flickr.com/photos/davemorris/316429534/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/davemorris/316429534/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><h2 id="_45-3-wortliste" tabindex="-1">45.3. Wortliste <a class="header-anchor" href="#_45-3-wortliste" aria-label="Permalink to &quot;45.3. Wortliste&quot;">​</a></h2><p>वा ... वा : entweder ... oder</p><h2 id="_45-4-ubung" tabindex="-1">45.4. Übung <a class="header-anchor" href="#_45-4-ubung" aria-label="Permalink to &quot;45.4. Übung&quot;">​</a></h2><p>A) Übersetzen Sie ins Sanskrit (für Vergangenheitsformen bitte das Imperfekt &lt;लङ्&gt; verwenden):</p><p>1. Du spaltest die (buddhistische) Gemeinde.</p><blockquote><p>zur Gemeindespaltung (सङ्घभेद) siehe:</p><blockquote><p><strong>Payer, Alois &lt;1944 - &gt;:</strong> Vinayamukha : Grundbegriffe der Ordensregeln und des Ordensrechts des Theravāda. -- Teil I. -- (Materialien zu den Grundbegriffen des Buddhismus). -- <em>URL</em>: <a href="http://www.payer.de/buddhgrund/vinaya01.htm" target="_blank" rel="noreferrer">http://www.payer.de/buddhgrund/vinaya01.htm</a></p></blockquote></blockquote><p>2. Habt ihr die Erde genossen?</p><p>3. Hast du vom König eine Gabe empfangen?</p><p>4. Heiliger Mann, warum fürchtest du dich nicht vor Gefahren?</p><p>5. Vater, wohin verlässt du die Familie?</p><p>6. Śūdrafrau, hast du die Last ins Haus des reichen Brahmanen getragen?</p><p>7. Göttin, du solltest den Wunsch nach Glück des Vaiśya, der Verdienstvolles getan hat, erfüllen.</p><p>8. Elefanten, ihr solltet die Fesseln nicht zerbrechen.</p><p>9. Du löwengleicher Mann, warum richtest du nicht deine ganze Aufmerksamkeit auf das Absolute (Brahman)?</p><p>10. Hast du, Dichter, die Welten gemessen?</p><p>B) Übersetzen Sie:</p><p>अर्जुन हतो वा प्राप्स्यसि स्वर्गं जित्वा वा भोक्ष्यसे महीं । तस्माद्भवता योध्यम् ॥१॥</p><p>भवति कथमनन्तदुःखमरुणत् ॥२॥</p><p>ब्राह्मण किमग्नौ घृतमजुहोः ॥३॥</p><p>शत्रो शस्तेण जीवं न छिनत्सि ॥४॥</p><p><img src="'+i+'" alt=""><br> Abb.: कन्ये किं लिखसि<br> [Bildquelle: John Isaac / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2348425672/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2348425672/</a>. -- Zugriff am 2009-01-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',45)])])}const c=d(s,[["render",l]]);export{k as __pageData,c as default};
